import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long low = 1;
        long high = edges.length > 0 ? edges[edges.length - 1][2] : 0;
        long answer = high;
        while (low <= high) {
            long mid = (low + high) / 2;
            DSU dsu = new DSU((int) n);
            for (long[] e : edges) {
                if (e[2] <= mid) {
                    dsu.union((int) e[0], (int) e[1]);
                }
            }
            long components = dsu.countComponents();
            if (components <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return answer;
    }

    static class DSU {
        int[] parent;
        int[] rank;

        DSU(int n) {
            parent = new int[n];
            rank = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        void union(int x, int y) {
            int xroot = find(x);
            int yroot = find(y);
            if (xroot == yroot) return;
            if (rank[xroot] < rank[yroot]) {
                parent[xroot] = yroot;
            } else {
                parent[yroot] = xroot;
                if (rank[xroot] == rank[yroot]) {
                    rank[xroot]++;
                }
            }
        }

        int countComponents() {
            Set<Integer> roots = new HashSet<>();
            for (int i = 0; i < parent.length; i++) {
                roots.add(find(i));
            }
            return roots.size();
        }
    }
}
