import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long low = 1;
        long high = edges.length == 0 ? 0 : edges[edges.length - 1][2];
        long answer = high;

        while (low <= high) {
            long mid = (low + high) / 2;
            int[] parent = new int[(int) n];
            int[] rank = new int[(int) n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }

            for (long[] edge : edges) {
                if (edge[2] <= mid) {
                    int x = (int) edge[0];
                    int y = (int) edge[1];
                    int xroot = find(parent, x);
                    int yroot = find(parent, y);
                    if (xroot != yroot) {
                        if (rank[xroot] < rank[yroot]) {
                            parent[xroot] = yroot;
                        } else {
                            parent[yroot] = xroot;
                            if (rank[xroot] == rank[yroot]) {
                                rank[xroot]++;
                            }
                        }
                    }
                }
            }

            int components = countComponents(parent, n);
            if (components <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return answer;
    }

    private static int find(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }

    private static int countComponents(int[] parent, int n) {
        Set<Integer> roots = new HashSet<>();
        for (int i = 0; i < n; i++) {
            roots.add(find(parent, i));
        }
        return roots.size();
    }
}
